// -*- coding: utf-8 -*-
from typing import List

import sys

class Solution:
    def solve(self, graph, node, visited, recStack):
        if visited[node]: return False

        visited[node] = True
        recStack[node] = True
        for neighbor in graph[node]:
            if self.solve(graph, neighbor, visited, recStack):
                return recStack[node] = True
        return False

    def detectCycle(self, n, edges):
        graph = [[] for _ in range(n)]
        for edge in edges:
            graph[edge[0]].append(edge[1])
            graph[edge[1]].append(edge[0])
        visited = [False]*n
        recStack = [False]*n
        for i in range(n):
            visited[i] = False
            recStack[i] = False
        for i in range(n):
            if not visited[i] and self.solve(graph, i, visited, recStack):
                return True
        return False

if __name__ == '__main__':
    n = int(input())
    edges = [list(map(int, input().split())) for _ in range(int(input()))]
    solution = Solution()
    print(solution.detectCycle(n, edges))

