    int n, m;
    scanf("%d %d", &n, &m);
    vector<set<int>> edges(m);
    for (int i = 0; i < m; ++i) {
        int a, b;
        scanf("%d %d", &a, &b);
        edges[i].insert(a);
        edges[i].insert(b);
    }
    vector<set<int>> graph(n);
    for (int i = 0; i < m; ++i) {
        graph[edges[i][0]].insert(edges[i][1]);
        graph[edges[i][1]].insert(edges[i][0]);
    }
    bool visited[MAXN], recStack[MAXN];
    for (int i = 0; i < n; ++i) {
        visited[i] = false;
        recStack[i] = false;
    }
    for (int i = 0; i < n; ++i) {
        if (!visited[i] && solve(graph, i, visited, recStack)) {
